class ExcelTemplateExporter{constructor(options={}){this.options={schema:options.schema||null,fileName:options.fileName||null,sheetName:options.sheetName||null,headerStyle:options.headerStyle||{fill:{type:"pattern",pattern:"solid",fgColor:{argb:"FFFFFF00"}},font:{bold:true,size:12},border:{top:{style:"thin"},left:{style:"thin"},bottom:{style:"thin"},right:{style:"thin"}},alignment:{horizontal:"center",vertical:"middle"}},freezeHeader:options.freezeHeader!==false,...options,};this.dependenciesLoaded=false;this.loadingPromise=null;}async startExport(){try{if(!this.options.schema){throw new Error("未提供 schema 对象");}this.showMessage("开始生成 Excel 模板...","info");await this.ensureDependencies();const buffer=await this.generateExcel();const fileName=this.getFileName();this.downloadExcel(buffer,fileName);this.showMessage(`Excel 模板生成成功：${fileName}`,"success");}catch(error){console.error("生成 Excel 模板失败:",error);this.showMessage("生成 Excel 模板失败："+error.message,"error");}}async ensureDependencies(){if(this.dependenciesLoaded)return;if(this.loadingPromise)return this.loadingPromise;this.loadingPromise=this.loadDependencies();await this.loadingPromise;this.dependenciesLoaded=true;}loadDependencies(){return new Promise((resolve,reject)=>{if(typeof ExcelJS!=="undefined"){resolve();return;}const script=document.createElement("script");script.src="https://fastly.jsdelivr.net/gh/crud1024/ng-script@main/Utils/ExcelJS/ V1/exceljs.min.js";script.onload=()=>{if(typeof ExcelJS!=="undefined"){resolve();}else{reject(new Error("ExcelJS 加载后未定义"));}};script.onerror=()=>reject(new Error("加载 ExcelJS 失败，请检查网络"));document.head.appendChild(script);});}async generateExcel(){const schema=this.options.schema;const sheetName=this.options.sheetName||schema.bindtable||"Sheet1";const dataColumns=schema.columns.filter((col)=>col.header&&col.xtype!=="rownumberer");const columnHeaders=dataColumns.map((col)=>col.header);const workbook=new ExcelJS.Workbook();const worksheet=workbook.addWorksheet(sheetName);worksheet.columns=columnHeaders.map((header)=>({header:header,key:header,width:20,}));dataColumns.forEach((col,index)=>{if(col.width){worksheet.getColumn(index+1).width=col.width/7;}});const headerRow=worksheet.getRow(1);const headerStyle=this.options.headerStyle;headerRow.eachCell((cell)=>{if(headerStyle.fill)cell.fill=headerStyle.fill;if(headerStyle.font)cell.font=headerStyle.font;if(headerStyle.border)cell.border=headerStyle.border;if(headerStyle.alignment)cell.alignment=headerStyle.alignment;});if(this.options.freezeHeader){worksheet.views=[{state:"frozen",xSplit:0,ySplit:1,activeCell:"A2"},];}return await workbook.xlsx.writeBuffer();}getFileName(){if(this.options.fileName){return this.options.fileName;}const schema=this.options.schema;const baseName=schema&&schema.bindtable?schema.bindtable:"template";return`${baseName}_模板.xlsx`;}downloadExcel(buffer,fileName){const blob=new Blob([buffer],{type:"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",});const url=window.URL.createObjectURL(blob);const link=document.createElement("a");link.href=url;link.download=fileName;document.body.appendChild(link);link.click();document.body.removeChild(link);window.URL.revokeObjectURL(url);}showMessage(message,type="info"){console.log(`[${type.toUpperCase()}]`,message);}}if(typeof window!=="undefined"){window.ExcelTemplateExporter=ExcelTemplateExporter;}
